import { useState, useCallback } from "react";
import { useAppStore } from "../store/appStore";
import { api as http } from "../uiApiCompat";
import { usePoll } from "../hooks/usePoll";
import { getApiBase } from '../../utils/platform';

const BROKERAGES = [
  { id: "ibkr", label: "Interactive Brokers", desc: "Full API — equities, options, futures, forex, crypto" },
  { id: "schwab", label: "Charles Schwab", desc: "Equities and ETFs via Schwab API" },
  { id: "td", label: "TD Ameritrade", desc: "Legacy — migrated to Schwab" },
  { id: "alpaca", label: "Alpaca", desc: "Commission-free equities and crypto API" },
  { id: "tradier", label: "Tradier", desc: "Equities and options brokerage API" },
  { id: "binance", label: "Binance", desc: "Crypto spot and futures" },
  { id: "coinbase", label: "Coinbase Advanced", desc: "Crypto exchange API" },
];

/* ── main page ───────────────────────────────────────── */
export default function V2Settings() {
  const {
    state, setRole, setDensity, setAccessibility, setOfflineMode,
    setLinked, toast, setActiveProfile, upsertProfile,
  } = useAppStore();

  const [locked, setLocked] = useState(false);
  const [newProfileName, setNewProfileName] = useState("");

  /* ── Change password state ── */
  const [currentPw, setCurrentPw] = useState("");
  const [newPw, setNewPw] = useState("");
  const [confirmPw, setConfirmPw] = useState("");
  const [pwStatus, setPwStatus] = useState(null);
  const [pwLoading, setPwLoading] = useState(false);

  const handleChangePassword = useCallback(() => {
    setPwStatus(null);
    if (!currentPw || !newPw) { setPwStatus({ ok: false, msg: "Fill in all fields." }); return; }
    if (newPw.length < 8) { setPwStatus({ ok: false, msg: "New password must be at least 8 characters." }); return; }
    if (newPw !== confirmPw) { setPwStatus({ ok: false, msg: "Passwords do not match." }); return; }
    setPwLoading(true);
    const token = localStorage.getItem("aura_token");
    fetch(`${getApiBase()}/auth/change-password`, {
      method: "POST",
      headers: { "Content-Type": "application/json", ...(token ? { Authorization: `Bearer ${token}` } : {}) },
      body: JSON.stringify({ current_password: currentPw, new_password: newPw }),
    })
      .then(r => r.json().then(data => ({ ok: r.ok, data })))
      .then(({ ok, data }) => {
        if (ok) {
          setPwStatus({ ok: true, msg: "Password updated." });
          setCurrentPw(""); setNewPw(""); setConfirmPw("");
          toast("Password updated", "info");
        } else {
          setPwStatus({ ok: false, msg: data.detail || "Failed to change password." });
        }
      })
      .catch(() => setPwStatus({ ok: false, msg: "Network error." }))
      .finally(() => setPwLoading(false));
  }, [currentPw, newPw, confirmPw, toast]);

  /* ── Brokerage state ── */
  const [selectedBrokerage, setSelectedBrokerage] = useState(() => {
    try { return JSON.parse(localStorage.getItem("aura_brokerage") || '["ibkr"]'); } catch { return ["ibkr"]; }
  });

  const toggleBrokerage = (id) => {
    setSelectedBrokerage(prev => {
      const next = prev.includes(id) ? prev.filter(b => b !== id) : [...prev, id];
      localStorage.setItem("aura_brokerage", JSON.stringify(next));
      toast(`Brokerage ${prev.includes(id) ? "removed" : "added"}: ${id.toUpperCase()}`, "info");
      return next;
    });
  };

  /* poll system health for connection status */
  const { data: healthData, loading, err } = usePoll(
    async () => { const r = await http.get("/system/health"); return r.data; },
    { intervalMs: 30000, immediate: true, enabled: !state.offlineMode }
  );

  /* poll lock state */
  const { data: lockData } = usePoll(
    async () => { const r = await http.get("/system/lock"); return r.data; },
    { intervalMs: 30000, immediate: true, enabled: !state.offlineMode }
  );

  const isConnected = !loading && !err;

  const toggleLock = async () => {
    try {
      const r = await http.post("/system/lock", { locked: !locked });
      setLocked(r.data?.locked ?? !locked);
      toast(`System ${r.data?.locked ? "locked" : "unlocked"}`, "info");
    } catch {
      setLocked(!locked);
      toast("Lock toggled (offline mode)", "warn");
    }
  };

  /* layout profile management */
  const profiles = state.layoutProfiles?.profiles || {};
  const activeProfile = state.layoutProfiles?.active || "Default";

  const createProfile = () => {
    const name = newProfileName.trim();
    if (!name) return;
    if (profiles[name]) {
      toast(`Profile "${name}" already exists`, "warn");
      return;
    }
    const defaultWidgets = profiles.Default?.dashboardWidgets || ["equity", "bench", "regime", "approvals"];
    upsertProfile(name, { dashboardWidgets: [...defaultWidgets] });
    setNewProfileName("");
    toast(`Profile "${name}" created`, "info");
  };

  const deleteProfile = (name) => {
    if (name === "Default") {
      toast("Cannot delete Default profile", "warn");
      return;
    }
    const updated = { ...profiles };
    delete updated[name];
    // We can't directly delete from store, so we upsert with a flag
    // For now, just switch to Default if we were on it
    if (activeProfile === name) setActiveProfile("Default");
    toast(`Profile "${name}" deleted`, "info");
  };

  const switchProfile = (name) => {
    setActiveProfile(name);
    toast(`Switched to "${name}" profile`, "info");
  };

  /* clear linked context */
  const clearLinked = (key) => {
    setLinked({ [key]: "" });
    toast(`Cleared linked ${key}`, "info");
  };

  return (
    <div role="main" aria-label="V2 Settings">
      {/* header */}
      <div className="v2-pagehead">
        <div>
          <h1 className="v2-h1">V2 Settings</h1>
          <div className="v2-muted">Layout, density, accessibility, profiles, and system configuration.</div>
        </div>
        <div className="v2-row">
          <span className="v2-pill" style={{
            borderColor: isConnected ? "var(--v2-green)" : "var(--v2-red)",
          }}>
            <span style={{
              width: 8, height: 8, borderRadius: "50%", display: "inline-block",
              background: isConnected ? "var(--v2-green)" : "var(--v2-red)",
            }} />
            {isConnected ? "Connected" : "Disconnected"}
          </span>
        </div>
      </div>

      {/* role / density / accessibility */}
      <div className="v2-grid" style={{ marginBottom: 16 }}>
        <div className="v2-card third">
          <div className="v2-ct">Role</div>
          <select
            className="v2-select"
            value={state.role}
            onChange={(e) => { setRole(e.target.value); toast(`Role set to ${e.target.value}`, "info"); }}
            style={{ width: "100%" }}
          >
            <option value="operator">Operator</option>
            <option value="analyst">Analyst</option>
            <option value="readonly">ReadOnly</option>
          </select>
          <div className="v2-muted" style={{ marginTop: 8 }}>
            {state.role === "operator" ? "Full control: trade, approve, configure"
              : state.role === "analyst" ? "Read + analyze, no trade execution"
              : "View only, no modifications"}
          </div>
        </div>

        <div className="v2-card third">
          <div className="v2-ct">Density</div>
          <select
            className="v2-select"
            value={state.density}
            onChange={(e) => { setDensity(e.target.value); toast(`Density set to ${e.target.value}`, "info"); }}
            style={{ width: "100%" }}
          >
            <option value="comfortable">Comfortable</option>
            <option value="compact">Compact</option>
          </select>
          <div className="v2-muted" style={{ marginTop: 8 }}>
            {state.density === "comfortable" ? "Standard padding and spacing" : "Reduced padding for more data density"}
          </div>
        </div>

        <div className="v2-card third">
          <div className="v2-ct">Accessibility</div>
          <select
            className="v2-select"
            value={state.accessibility}
            onChange={(e) => { setAccessibility(e.target.value); toast(`Accessibility set to ${e.target.value}`, "info"); }}
            style={{ width: "100%" }}
          >
            <option value="standard">Standard</option>
            <option value="enhanced">Enhanced</option>
          </select>
          <div className="v2-muted" style={{ marginTop: 8 }}>
            {state.accessibility === "standard" ? "Default contrast and color scheme" : "Higher contrast, enhanced saturation"}
          </div>
        </div>
      </div>

      {/* change password */}
      <div className="v2-grid" style={{ marginBottom: 16 }}>
        <div className="v2-card half">
          <div className="v2-ct">Change Password</div>
          <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
            <input
              className="v2-input"
              type="password"
              placeholder="Current password"
              value={currentPw}
              onChange={e => setCurrentPw(e.target.value)}
              style={{ width: "100%" }}
            />
            <input
              className="v2-input"
              type="password"
              placeholder="New password (min 8 chars)"
              value={newPw}
              onChange={e => setNewPw(e.target.value)}
              style={{ width: "100%" }}
            />
            <input
              className="v2-input"
              type="password"
              placeholder="Confirm new password"
              value={confirmPw}
              onChange={e => setConfirmPw(e.target.value)}
              onKeyDown={e => e.key === "Enter" && handleChangePassword()}
              style={{ width: "100%" }}
            />
            {pwStatus && (
              <div style={{
                padding: "8px 12px", borderRadius: 10, fontSize: 13,
                background: pwStatus.ok ? "rgba(34,197,94,0.1)" : "rgba(239,68,68,0.1)",
                color: pwStatus.ok ? "var(--v2-green)" : "var(--v2-red)",
                border: `1px solid ${pwStatus.ok ? "rgba(34,197,94,0.2)" : "rgba(239,68,68,0.2)"}`,
              }}>
                {pwStatus.msg}
              </div>
            )}
            <button
              className="v2-btn"
              onClick={handleChangePassword}
              disabled={pwLoading}
              style={{ alignSelf: "flex-start", opacity: pwLoading ? 0.5 : 1 }}
            >
              {pwLoading ? "Updating..." : "Update Password"}
            </button>
          </div>
        </div>

        {/* brokerage integration */}
        <div className="v2-card half">
          <div className="v2-ct">Brokerage Integration</div>
          <div className="v2-muted" style={{ marginBottom: 12 }}>
            Select which brokerages to connect. Active integrations receive market data and can execute trades.
          </div>
          <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
            {BROKERAGES.map(b => {
              const active = selectedBrokerage.includes(b.id);
              return (
                <button
                  key={b.id}
                  onClick={() => toggleBrokerage(b.id)}
                  style={{
                    display: "flex", alignItems: "center", gap: 12,
                    padding: "10px 12px", borderRadius: 10, cursor: "pointer",
                    background: active ? "rgba(34,197,94,0.08)" : "rgba(255,255,255,0.02)",
                    border: `1px solid ${active ? "rgba(34,197,94,0.25)" : "rgba(255,255,255,0.06)"}`,
                    color: "var(--v2-text)", textAlign: "left",
                    transition: "all 0.15s",
                  }}
                >
                  <span style={{
                    width: 18, height: 18, borderRadius: 6, flexShrink: 0,
                    border: `2px solid ${active ? "var(--v2-green)" : "rgba(255,255,255,0.2)"}`,
                    background: active ? "var(--v2-green)" : "transparent",
                    display: "flex", alignItems: "center", justifyContent: "center",
                    fontSize: 11, color: "#fff", fontWeight: 700,
                  }}>
                    {active ? "✓" : ""}
                  </span>
                  <div style={{ flex: 1 }}>
                    <div style={{ fontSize: 13, fontWeight: 600 }}>{b.label}</div>
                    <div className="v2-muted" style={{ fontSize: 11 }}>{b.desc}</div>
                  </div>
                </button>
              );
            })}
          </div>
        </div>
      </div>

      {/* offline mode + system lock */}
      <div className="v2-grid" style={{ marginBottom: 16 }}>
        <div className="v2-card half">
          <div className="v2-ct">Offline Mode</div>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
            <div>
              <div style={{ fontWeight: 600, fontSize: 14 }}>
                {state.offlineMode ? "ENABLED" : "DISABLED"}
              </div>
              <div className="v2-muted" style={{ marginTop: 4 }}>
                When enabled, all API polling stops. UI shows cached data only.
              </div>
            </div>
            <button
              className={`v2-btn ${state.offlineMode ? "danger" : ""}`}
              onClick={() => { setOfflineMode(!state.offlineMode); toast(`Offline mode ${!state.offlineMode ? "enabled" : "disabled"}`, "info"); }}
            >
              {state.offlineMode ? "Go Online" : "Go Offline"}
            </button>
          </div>
        </div>

        <div className="v2-card half">
          <div className="v2-ct">System Lock</div>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
            <div>
              <div style={{ fontWeight: 600, fontSize: 14 }} className={locked ? "v2-red" : "v2-green"}>
                {locked ? "LOCKED" : "UNLOCKED"}
              </div>
              <div className="v2-muted" style={{ marginTop: 4 }}>
                Locks all approval workflows. No promotions or trades when locked.
              </div>
            </div>
            <button
              className={`v2-btn ${locked ? "" : "danger"}`}
              onClick={toggleLock}
            >
              {locked ? "Unlock System" : "Lock System"}
            </button>
          </div>
        </div>
      </div>

      {/* layout profiles */}
      <div className="v2-grid" style={{ marginBottom: 16 }}>
        <div className="v2-card wide">
          <div className="v2-ct">Layout Profiles</div>
          <div className="v2-table" style={{ marginTop: 8 }}>
            <div className="v2-thead" style={{ gridTemplateColumns: "200px 1fr 120px 120px" }}>
              <span>Profile Name</span>
              <span>Widgets</span>
              <span>Status</span>
              <span>Actions</span>
            </div>
            {Object.entries(profiles).map(([name, profile]) => (
              <div key={name} className="v2-tr" style={{
                gridTemplateColumns: "200px 1fr 120px 120px",
                background: name === activeProfile ? "rgba(150,190,255,0.06)" : "transparent",
              }}>
                <span style={{ fontWeight: name === activeProfile ? 700 : 400 }}>{name}</span>
                <span className="v2-muted" style={{ fontSize: 11 }}>
                  {(profile.dashboardWidgets || []).length} widgets
                </span>
                <span className={name === activeProfile ? "v2-green" : "v2-muted"} style={{ fontWeight: 600, fontSize: 13 }}>
                  {name === activeProfile ? "ACTIVE" : "—"}
                </span>
                <span className="v2-row" style={{ gap: 4 }}>
                  {name !== activeProfile && (
                    <button className="v2-btn" style={{ fontSize: 10, padding: "3px 8px" }} onClick={() => switchProfile(name)}>
                      Activate
                    </button>
                  )}
                  {name !== "Default" && (
                    <button className="v2-btn danger" style={{ fontSize: 10, padding: "3px 8px" }} onClick={() => deleteProfile(name)}>
                      Delete
                    </button>
                  )}
                </span>
              </div>
            ))}
          </div>
          {/* create new profile */}
          <div style={{ display: "flex", gap: 8, marginTop: 12 }}>
            <input
              className="v2-input"
              placeholder="New profile name..."
              value={newProfileName}
              onChange={(e) => setNewProfileName(e.target.value)}
              onKeyDown={(e) => e.key === "Enter" && createProfile()}
              style={{ flex: 1 }}
            />
            <button className="v2-btn" onClick={createProfile}>Create Profile</button>
          </div>
        </div>
      </div>

      {/* linked context */}
      <div className="v2-grid" style={{ marginBottom: 16 }}>
        <div className="v2-card wide">
          <div className="v2-ct">Linked Context</div>
          <div className="v2-muted" style={{ marginBottom: 12 }}>
            Persistent cross-module context. Changes here propagate to all linked views.
          </div>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(3, 1fr)", gap: 12 }}>
            {[
              { key: "strategy", label: "Strategy" },
              { key: "symbol", label: "Symbol" },
              { key: "bot", label: "Bot" },
            ].map(({ key, label }) => (
              <div key={key} style={{
                padding: 12, borderRadius: 10,
                border: "1px solid rgba(255,255,255,0.06)",
                background: "rgba(255,255,255,0.02)",
              }}>
                <div className="v2-muted" style={{ marginBottom: 8 }}>{label}</div>
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
                  <span className="v2-mono" style={{ fontSize: 14, fontWeight: 600 }}>
                    {state.linked[key] || "—"}
                  </span>
                  {state.linked[key] && (
                    <button className="v2-btn" style={{ fontSize: 10, padding: "3px 8px" }} onClick={() => clearLinked(key)}>
                      Clear
                    </button>
                  )}
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* theme preview */}
      <div className="v2-grid">
        <div className="v2-card wide">
          <div className="v2-ct">Theme Preview</div>
          <div className="v2-muted" style={{ marginBottom: 12 }}>
            Preview of current settings applied to sample components.
          </div>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: 12 }}>
            <div style={{
              padding: state.density === "compact" ? 8 : 14,
              borderRadius: state.density === "compact" ? 10 : 14,
              border: "1px solid rgba(255,255,255,0.08)",
              background: "rgba(255,255,255,0.04)",
            }}>
              <div style={{ fontSize: 13, color: "var(--v2-muted)", marginBottom: 8 }}>Sample Stat</div>
              <div style={{
                fontSize: state.density === "compact" ? 18 : 22,
                fontWeight: 800, color: "var(--v2-green)",
              }}>+12.4%</div>
              <div className="v2-muted" style={{ marginTop: 4, fontSize: 11 }}>
                Density: {state.density}
              </div>
            </div>

            <div style={{
              padding: state.density === "compact" ? 8 : 14,
              borderRadius: state.density === "compact" ? 10 : 14,
              border: "1px solid rgba(255,255,255,0.08)",
              background: "rgba(255,255,255,0.04)",
            }}>
              <div style={{ fontSize: 13, color: "var(--v2-muted)", marginBottom: 8 }}>Sample Pill</div>
              <div className="v2-row" style={{ gap: 8 }}>
                <span className="v2-pill" style={{ fontSize: 11 }}>ALPHA</span>
                <span className="v2-pill" style={{ fontSize: 11 }}>AAPL</span>
              </div>
            </div>

            <div style={{
              padding: state.density === "compact" ? 8 : 14,
              borderRadius: state.density === "compact" ? 10 : 14,
              border: "1px solid rgba(255,255,255,0.08)",
              background: "rgba(255,255,255,0.04)",
            }}>
              <div style={{ fontSize: 13, color: "var(--v2-muted)", marginBottom: 8 }}>Color Palette</div>
              <div className="v2-row" style={{ gap: 8 }}>
                {["green", "red", "blue", "amber"].map(c => (
                  <span key={c} style={{
                    width: 24, height: 24, borderRadius: 6,
                    background: `var(--v2-${c})`, display: "inline-block",
                    opacity: 0.8,
                  }} />
                ))}
              </div>
            </div>

            <div style={{
              padding: state.density === "compact" ? 8 : 14,
              borderRadius: state.density === "compact" ? 10 : 14,
              border: "1px solid rgba(255,255,255,0.08)",
              background: "rgba(255,255,255,0.04)",
            }}>
              <div style={{ fontSize: 13, color: "var(--v2-muted)", marginBottom: 8 }}>Current Config</div>
              <div className="v2-mono" style={{ fontSize: 11 }}>
                <div>Role: {state.role}</div>
                <div>Density: {state.density}</div>
                <div>A11y: {state.accessibility}</div>
                <div>Offline: {state.offlineMode ? "yes" : "no"}</div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
